@namespace sv_da549c8e50bd418cb8a82a9f056cd9f5.Components.Catalog

<div class="d-flex justify-content-between align-items-center mb-3">
    <div>
        <label class="form-label mb-0 me-2 fw-semibold">Sort by:</label>
        <select class="form-select form-select-sm d-inline-block w-auto"
                value="@SortBy"
                @onchange="HandleSortChange">
            @foreach (var option in SortOptions)
            {
                <option value="@option.Value">@option.Label</option>
            }
        </select>
    </div>
    <span class="text-muted">
        @if (TotalCount > 0)
        {
            var first = (Page - 1) * PageSize + 1;
            var last = Math.Min(Page * PageSize, TotalCount);
            <text>Showing @first–@last of @TotalCount products</text>
        }
        else
        {
            <text>No products found</text>
        }
    </span>
</div>

@code {
    [Parameter]
    public string SortBy { get; set; } = "price_asc";

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int Page { get; set; } = 1;

    [Parameter]
    public int PageSize { get; set; } = 12;

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private static readonly (string Value, string Label)[] SortOptions =
    [
        ("price_asc", "Price: Low to High"),
        ("price_desc", "Price: High to Low"),
        ("name_asc", "Name: A-Z"),
        ("rating_desc", "Rating: Highest")
    ];

    private async Task HandleSortChange(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}

@namespace sv_da549c8e50bd418cb8a82a9f056cd9f5.Components.Catalog

@if (TotalPages > 1)
{
    <nav aria-label="Product catalog pagination" class="mt-4">
        <ul class="pagination justify-content-center mb-0">
            <li class="page-item @(Page <= 1 ? "disabled" : "")">
                <button class="page-link" disabled="@(Page <= 1)"
                        @onclick="() => GoToPage(Page - 1)">Previous</button>
            </li>
            @foreach (var p in GetPageNumbers())
            {
                <li class="page-item @(p == Page ? "active" : "")">
                    <button class="page-link" @onclick="() => GoToPage(p)">@p</button>
                </li>
            }
            <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
                <button class="page-link" disabled="@(Page >= TotalPages)"
                        @onclick="() => GoToPage(Page + 1)">Next</button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter]
    public int Page { get; set; } = 1;

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int PageSize { get; set; } = 12;

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private int TotalPages => PageSize > 0 ? (int)Math.Ceiling((double)TotalCount / PageSize) : 1;

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != Page)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }

    private IEnumerable<int> GetPageNumbers()
    {
        // Show up to 7 page buttons, centered around current page
        const int maxVisible = 7;
        int start = Math.Max(1, Page - maxVisible / 2);
        int end = Math.Min(TotalPages, start + maxVisible - 1);
        start = Math.Max(1, end - maxVisible + 1);

        for (int i = start; i <= end; i++)
            yield return i;
    }
}

