+
+    private async Task HandleFilterApplied(ProductFilter filter)
+    {
+        _filter = filter;
+        _page = 1;
+        await SearchAsync();
+    }
+
+    private async Task HandleFilterCleared()
+    {
+        _filter = new ProductFilter(null, null, null, false);
+        _page = 1;
+        await SearchAsync();
+    }
+
+    private async Task HandleSortChanged(string sortBy)
+    {
+        _sortBy = sortBy;
+        _page = 1;
+        await SearchAsync();
+    }
+
+    private async Task HandlePageChanged(int page)
+    {
+        _page = page;
+        await SearchAsync();
+    }
+
+    private async Task HandleProductSelected(Product product)
+    {
+        await OnProductSelected.InvokeAsync(product);
+    }
+
+    private async Task HandleAddToCart(Product product)
+    {
+        await OnAddToCart.InvokeAsync(product);
+    }
+
+    private async Task RetryLoad()
+    {
+        await LoadDataAsync();
+    }
+}
